import pytest

AC_UID = "ac5-20260521-090100-skillmd-matches-codexmd"
AC_TYPE = "data"


def test_AC5():
    """
    GIVEN: /root/.agents/skills/codex/SKILL.md after the change
    WHEN:  Step 2 path-resolution block is compared to commands/codex.md Step 2
    THEN:  both contain the same path-safety guard (including '.' and '..' exclusion) and same branch structure; AND SKILL.md Source: cross-link at line 8 is preserved unchanged
    """
    # TODO(dev): replace the line below with the real test body. While the
    # TEST_INCOMPLETE sentinel is present the test will hard-fail, marking
    # the AC as unimplemented for QA Phase 5.
    import os, re
    codex_file = os.path.join(os.path.dirname(__file__), "..", "..", "..", "commands", "codex.md")
    skill_file = "/root/.agents/skills/codex/SKILL.md"

    def extract_step2_block(filepath):
        with open(filepath) as f:
            content = f.read()
        start = content.find("### 2. Generate unique output path")
        end = content.find("### 3. Review mode")
        assert start != -1, f"Step 2 heading not found in {filepath}"
        assert end != -1, f"Step 3 heading not found in {filepath}"
        return content[start:end]

    codex_step2 = extract_step2_block(codex_file)
    skill_step2 = extract_step2_block(skill_file)

    # Both must have the same path-safety guard (base regex)
    assert "A-Za-z0-9._-" in skill_step2, "SKILL.md Step 2 missing ^[A-Za-z0-9._-]+$ safety regex"

    # Both must have explicit . rejection
    assert '!= "."' in skill_step2 or "!= '.'" in skill_step2, (
        'SKILL.md Step 2 missing explicit != "." guard'
    )
    # Both must have explicit .. rejection (Codex CF-2)
    assert '!= ".."' in skill_step2 or "!= '..'" in skill_step2, (
        'SKILL.md Step 2 missing explicit != ".." guard'
    )

    # Both must have canonical path shape
    assert "docs/codex/$CODEX_OUT_TASK_ID" in skill_step2, (
        "SKILL.md Step 2 missing canonical docs/codex/$CODEX_OUT_TASK_ID path"
    )

    # Both must have the same branching structure (if/else)
    assert "if [" in skill_step2 or "if [[" in skill_step2, "SKILL.md Step 2 missing if-branch"
    assert "else" in skill_step2, "SKILL.md Step 2 missing else-branch"

    # Structural comparison: extract bash code blocks from both
    def extract_bash_block(text):
        """Extract content inside first ```bash ... ``` block."""
        m = re.search(r'```bash\n(.*?)```', text, re.DOTALL)
        return m.group(1).strip() if m else ""

    codex_bash = extract_bash_block(codex_step2)
    skill_bash = extract_bash_block(skill_step2)
    assert codex_bash == skill_bash, (
        f"SKILL.md Step 2 bash block differs from commands/codex.md Step 2 bash block.\n"
        f"codex.md:\n{codex_bash}\n\nSKILL.md:\n{skill_bash}"
    )

    # Source: cross-link must be preserved unchanged
    with open(skill_file) as f:
        skill_content = f.read()
    assert "Source: `/root/.claude/commands/codex.md`" in skill_content, (
        "SKILL.md Source: cross-link at line 8 is missing or changed"
    )
